SELECT * FROM exam
WHERE title ILIKE '%' || #{name} || '%'  


  AND category = #{category}  



  AND creater_id = CAST(#{creator} AS INTEGER)  



  AND created_at::text LIKE #{createdAt} || '%'  



  AND activation_status = #{activationStatus}  



  AND exam_time <= #{examTime}  



ORDER BY exam_time;

